// ════════════════════════════════════════════════════════
// ⚙️  PARÂMETROS — EDITE AQUI antes de executar
// ════════════════════════════════════════════════════════
const mes = 10;   // Mês de apuração (1-12)
const ano = 2025; // Ano de apuração

// Caminho ABSOLUTO do projeto no servidor onde o N8N está rodando
const project_dir = '/caminho/para/calculadora_comissoes';

// Caminhos dos arquivos de entrada (relativos a project_dir)
const caminho_ac  = 'dados_entrada/analise-comercial.xlsx';
const caminho_cp  = 'dados_entrada/Classificação de Produtos.xlsx';
const caminho_af  = 'dados_entrada/analise-financeira.xlsx';
const caminho_pc  = 'dados_entrada/processo_pedido_compra.xlsx';
const caminho_dev = 'dados_entrada/devolucoes.xlsx';

const mm = String(mes).padStart(2, '0');
return [{ json: {
  mes, ano, project_dir,
  caminho_ac, caminho_cp, caminho_af, caminho_pc, caminho_dev,
  saida_dir: `saida/${mm}_${ano}`,
  warnings_acumulados: [],
  errors_acumulados: [],
} }];

// ── Nó: Carregar Config ──────────────────────────────────────────────
// Chama receita/n8n/prep_config.py para carregar config do Supabase
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
const path = require('path');
const state = $input.all()[0].json;

const tmpIn  = path.join(os.tmpdir(), 'n8n_rec_config_in.json');
const tmpOut = path.join(os.tmpdir(), 'n8n_rec_config_out.json');

const payload = {
  project_dir: state.project_dir,
  mes: state.mes,
  ano: state.ano,
};
fs.writeFileSync(tmpIn, JSON.stringify(payload));

try {
  execSync(
    `python -m receita.n8n.prep_config < "${tmpIn}" > "${tmpOut}"`,
    { cwd: state.project_dir, encoding: 'utf8', shell: true }
  );
  const result = JSON.parse(fs.readFileSync(tmpOut, 'utf8'));
  if (result.status !== 'ok') {
    throw new Error('prep_config falhou: ' + JSON.stringify(result.errors));
  }
  const warnings = [...(state.warnings_acumulados || []), ...(result.warnings || [])];
  return [{ json: { ...state, ...result, warnings_acumulados: warnings } }];
} catch (e) {
  throw new Error('[Config] ' + (e.message || String(e)));
}

// ── Nó: Preparar Dados ───────────────────────────────────────────────
// Chama receita/n8n/prep_pipeline.py:
//   loader → atribuicao → realizados → serializa DataFrames
// ATENÇÃO: este nó pode demorar 10-60s dependendo do tamanho dos dados
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
const path = require('path');
const state = $input.all()[0].json;

const tmpIn  = path.join(os.tmpdir(), 'n8n_rec_prep_in.json');
const tmpOut = path.join(os.tmpdir(), 'n8n_rec_prep_out.json');

const payload = {
  project_dir: state.project_dir,
  mes: state.mes,
  ano: state.ano,
  caminho_ac:  state.caminho_ac,
  caminho_cp:  state.caminho_cp,
  caminho_af:  state.caminho_af,
  caminho_pc:  state.caminho_pc,
  caminho_dev: state.caminho_dev,
};
fs.writeFileSync(tmpIn, JSON.stringify(payload));

try {
  execSync(
    `python -m receita.n8n.prep_pipeline < "${tmpIn}" > "${tmpOut}"`,
    { cwd: state.project_dir, encoding: 'utf8', shell: true, timeout: 180000 }
  );
  const result = JSON.parse(fs.readFileSync(tmpOut, 'utf8'));
  if (result.status !== 'ok') {
    throw new Error('prep_pipeline falhou: ' + JSON.stringify(result.errors));
  }
  const warnings = [...(state.warnings_acumulados || []), ...(result.warnings || [])];
  return [{ json: { ...state, ...result, warnings_acumulados: warnings } }];
} catch (e) {
  throw new Error('[Prep Dados] ' + (e.message || String(e)));
}

// ── Etapa 03: Atribuir GLs ───────────────────────────────────────────
// Determina quais Gerentes de Linha são elegíveis para cada linha
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
const path = require('path');
const state = $input.all()[0].json;

const tmpIn  = path.join(os.tmpdir(), 'n8n_rec_e03_in.json');
const tmpOut = path.join(os.tmpdir(), 'n8n_rec_e03_out.json');

const payload = {
  config_comissao: state.config_comissao,
  colaboradores:   state.colaboradores,
  cargos:          state.cargos,
};
fs.writeFileSync(tmpIn, JSON.stringify(payload));

let result;
try {
  execSync(
    `python -m receita.pipeline.etapas.etapa_03_atribuir_gls < "${tmpIn}" > "${tmpOut}"`,
    { cwd: state.project_dir, encoding: 'utf8', shell: true }
  );
  result = JSON.parse(fs.readFileSync(tmpOut, 'utf8'));
} catch (e) {
  result = { status: 'error', errors: [String(e.message)], warnings: [] };
}

const warnings = [...(state.warnings_acumulados || []), ...(result.warnings || [])];
const errors   = [...(state.errors_acumulados   || []), ...(result.errors   || [])];
return [{ json: { ...state, ...result, warnings_acumulados: warnings, errors_acumulados: errors } }];

// ── Etapa 02: Validar Conflitos GL ───────────────────────────────────
// Detecta processos com múltiplos GLs em linhas diferentes
// NÃO crítico: conflitos viram warnings, pipeline continua
const { execSync } = require('child_process');
const fs = require('fs');
const os = require('os');
const path = require('path');
const state = $input.all()[0].json;

const tmpIn  = path.join(os.tmpdir(), 'n8n_rec_e02_in.json');
const tmpOut = path.join(os.tmpdir(), 'n8n_rec_e02_out.json');

const payload = {
  df_ac_json:       state.df_ac_full_json,
  atribuicao_result: state.atribuicao_result,
  saida_dir:        state.saida_dir,
  mes:              state.mes,
  ano:              state.ano,
};
fs.writeFileSync(tmpIn, JSON.stringify(payload));

let result;
try {
  execSync(
    `python -m receita.pipeline.etapas.etapa_02_validar_conflitos < "${tmpIn}" > "${tmpOut}"`,
    { cwd: state.project_dir, encoding: 'utf8', shell: true }
  );
  result = JSON.parse(fs.readFileSync(tmpOut, 'utf8'));
} catch (e) {
  // Falha não crítica — pipeline continua
  result = { status: 'warning', conflitos: [], processos_bloqueados: [], warnings: ['E02 falhou: ' + String(e.message)], errors: [] };
}

const warnings = [...(state.warnings_acumulados || []), ...(result.warnings || [])];
if ((result.conflitos || []).length > 0) {
  warnings.push(`⚠️ ${result.conflitos.length} conflito(s) GL detectado(s) — ver alertas_${String(state.mes).padStart(2,'0')}_${state.ano}.txt`);
}
return [{ json: { ...state, ...result, warnings_acumulados: warnings } }];

