const reconciliacao_result = state.reconciliacao_result || { total_por_gl: {} };
const total_reconciliacao  = Object.values(reconciliacao_result.total_por_gl || {}).reduce((a, b) => a + b, 0);

const estornos_result = state.estornos_result || { total_por_gl: {} };
const total_estornos  = Object.values(estornos_result.total_por_gl || {}).reduce((a, b) => a + b, 0);

const resumo = {
  pipeline: 'Comissões por Recebimento',
  mes_ano: `${String(state.mes).padStart(2,'0')}/${state.ano}`,
  status: 'concluido',
  resultados: {
    total_comissao_bruta:  Number(total_comissao.toFixed(2)),
    total_reconciliacao:   Number(total_reconciliacao.toFixed(2)),
    total_estornos:        Number(total_estornos.toFixed(2)),
    total_liquido:         Number((total_comissao + total_reconciliacao + total_estornos).toFixed(2)),
    num_documentos:        num_docs,
    num_gls:               num_gls,
    por_gl:                comissao_result.total_por_gl || {},
  },
  arquivos_gerados: {
    markdown: state.arquivos_md    || [],
    excel:    state.arquivos_excel || [],
    alertas:  state.arquivo_alerta ? [state.arquivo_alerta] : [],
  },
  warnings: state.warnings_acumulados || [],
  errors:   state.errors_acumulados   || [],
};

console.log('\n' + '='.repeat(60));
console.log(`  Pipeline Recebimento — ${resumo.mes_ano}`);
console.log('='.repeat(60));
console.log(`  Total comissão bruta:  R$ ${resumo.resultados.total_comissao_bruta.toLocaleString('pt-BR', {minimumFractionDigits:2})}`);
console.log(`  Reconciliação:         R$ ${resumo.resultados.total_reconciliacao.toLocaleString('pt-BR', {minimumFractionDigits:2})}`);
console.log(`  Estornos:              R$ ${resumo.resultados.total_estornos.toLocaleString('pt-BR', {minimumFractionDigits:2})}`);
console.log(`  Total líquido:         R$ ${resumo.resultados.total_liquido.toLocaleString('pt-BR', {minimumFractionDigits:2})}`);
console.log(`  Documentos processados: ${num_docs} | GLs: ${num_gls}`);
console.log(`  Arquivos MD:   ${(state.arquivos_md||[]).length}`);
console.log(`  Arquivos XLSX: ${(state.arquivos_excel||[]).length}`);
if ((resumo.warnings).length > 0) {
  console.log(`  ⚠️  ${resumo.warnings.length} aviso(s) — ver campo 'warnings' na saída`);
}

return [{ json: resumo }];
